mapper.select:
SELECT version_id AS versionId, version_code AS versionCode, version_name AS versionName, app_type AS appType, status, release_type AS releaseType, rollout_percent AS rolloutPercent, changelog, download_url AS downloadUrl, min_compatible_version AS minCompatibleVersion, feature_list AS featureList, deployed_by AS deployedBy, deployed_by_name AS deployedByName, deployed_time AS deployedTime, force_update AS forceUpdate, create_time AS createTime FROM sys_version
is_deleted = 0
AND app_type = #{req.appType}
AND status = #{req.status}
AND (version_code LIKE CONCAT('%', #{req.keyword}, '%') OR version_name LIKE CONCAT('%', #{req.keyword}, '%') OR changelog LIKE CONCAT('%', #{req.keyword}, '%'))
ORDER BY create_time DESC
